module top_module(invalid_out, in0, in1, in2, in3, select);output invalid_out;
input in0, in1, in2, in3;
input [1:0] select;

	reg invalid_out;

	always @ (select or in0 or in1 or in2 or in3) begin
		case (select)	
			2'b00:		invalid_out = in0;
			2'b01:		invalid_out = in1;
			2'b10:		invalid_out = in2;
			2'b11:		invalid_out = in3;

			default:	invalid_out = 1'hx;

		endcase
	end
endmodule
